import { useState, useRef } from "react";

/* ─── Data ─────────────────────────────────────────────────────────────── */
const MILES = [
  {
    id: "first",
    label: "First Mile",
    image: "/mile.png",
    items: [
      {
        num: 1,
        title: "Warehouse pickers",
        desc: "Responsible for sorting goods at origin warehouses before dispatch.",
      },
      {
        num: 2,
        title: "Dark-store associates",
        desc: "Operate out of high-density storage units in residential clusters.",
      },
      {
        num: 3,
        title: "Aggregation-hub handlers",
        desc: "Consolidate incoming shipments and prepare them for onward dispatch.",
      },
    ],
  },
  {
    id: "middle",
    label: "Middle Mile",
    image: "/mile.png",
    items: [
      {
        num: 1,
        title: "Truck drivers",
        desc: "Transport goods between warehouses, hubs, and cities.",
      },
      {
        num: 2,
        title: "Fleet operators",
        desc: "Manage movement from aggregation hubs to local distribution points.",
      },
    ],
  },
  {
    id: "last",
    label: "Last Mile",
    image: "/mile.png",
    items: [
      {
        num: 1,
        title: "Delivery partners",
        desc: "Handle final doorstep delivery — food, groceries, and parcels.",
      },
      {
        num: 2,
        title: "Hyperlocal riders",
        desc: "Factors such as high attrition, constant churn, frequent relocation, and flexible partner-based models (vs. full-time employment) increase verification complexity and compliance risk across these segments.",
      },
    ],
  },
];

/* ─── Content panel with slide animation ──────────────────────────────── */
function ContentPanel({ mile, direction }) {
  /* direction: "left" = entering from right, "right" = entering from left */
  return (
    <div
      key={mile.id}
      style={{
        display: "flex",
        gap: 60,
        alignItems: "flex-start",
        width: "100%",
        animation: `slide-in-${direction} 0.45s cubic-bezier(0.22,1,0.36,1) both`,
      }}
    >
      <style>{`
        @keyframes slide-in-left {
          from { opacity:0; transform:translateX(90px);  }
          to   { opacity:1; transform:translateX(0);     }
        }
        @keyframes slide-in-right {
          from { opacity:0; transform:translateX(-90px); }
          to   { opacity:1; transform:translateX(0);     }
        }
      `}</style>

      {/* ── Collage image ── */}
      <div style={{
        flexShrink: 0,
        width: 300, height: 320,
        borderRadius: 8,
        overflow: "hidden",
        border: "1px solid #e8e8e8",
        background: "#f5f3f0",
        position: "relative",
      }}>
        <img
          src={mile.image}
          alt="mile illustration"
          style={{
            width: "100%", height: "100%",
            objectFit: "cover",
            display: "block",
          }}
          onError={e => {
            /* Fallback: render the BW collage placeholder if image is missing */
            e.target.style.display = "none";
            e.target.nextSibling.style.display = "flex";
          }}
        />
        {/* Fallback collage placeholder */}
        <div style={{
          display: "none",
          position: "absolute", inset: 0,
          background: "linear-gradient(145deg,#ccc 0%,#aaa 60%,#999 100%)",
          alignItems: "center", justifyContent: "center",
          flexDirection: "column", gap: 8,
        }}>
          {/* Red accent */}
          <div style={{
            position: "absolute", top: 28, left: 22,
            width: 36, height: 36, background: "#e53e3e",
          }}/>
          {/* Blue accent */}
          <div style={{
            position: "absolute", bottom: 60, right: 24,
            width: 0, height: 0,
            borderLeft: "14px solid transparent",
            borderRight: "14px solid transparent",
            borderBottom: "24px solid #1a3a6b",
          }}/>
          {/* Car silhouette */}
          <div style={{
            width: 160, height: 70,
            background: "rgba(40,40,40,0.55)",
            borderRadius: "6px 6px 0 0",
            position: "absolute", bottom: 30, left: 20,
          }}/>
          {/* Insurance text strip */}
          <div style={{
            position: "absolute", bottom: 14, left: 16, right: 16,
            background: "rgba(255,255,255,0.85)",
            padding: "6px 10px", borderRadius: 3,
            fontSize: 10, color: "#333", fontStyle: "italic",
            fontFamily: "Georgia,serif",
          }}>Motor Insurance.</div>
          {/* Grid dots */}
          <div style={{
            position: "absolute", bottom: 50, right: 16,
            width: 40, height: 40,
            backgroundImage: "radial-gradient(circle, #999 1px, transparent 1px)",
            backgroundSize: "6px 6px",
            opacity: 0.5,
          }}/>
        </div>
      </div>

      {/* ── Right text ── */}
      <div style={{ flex: 1, paddingTop: 8 }}>
        {mile.items.map((item, i) => (
          <div key={i} style={{ marginBottom: 36 }}>
            <h3 style={{
              fontFamily: "'Playfair Display','Georgia',serif",
              fontSize: "clamp(18px,1.6vw,24px)",
              fontWeight: 700, color: "#1a3a6b",
              marginBottom: 10,
              display: "flex", gap: 6, alignItems: "baseline",
            }}>
              <span style={{ color: "#1a3a6b" }}>{item.num}.</span>
              {" "}{item.title}
            </h3>
            <p style={{
              fontSize: "clamp(14px,1.1vw,17px)",
              color: "#444", lineHeight: 1.75,
              fontFamily: "'Inter',sans-serif",
            }}>{item.desc}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

/* ─── Main section ─────────────────────────────────────────────────────── */
export default function PeopleSection() {
  const [active, setActive] = useState(0);      // current tab index
  const [prev, setPrev]     = useState(null);   // previous index (for direction)
  const [key, setKey]       = useState(0);      // forces re-mount = re-runs animation

  const handleTabClick = (idx) => {
    if (idx === active) return;
    setPrev(active);
    setActive(idx);
    setKey(k => k + 1);
  };

  /* Slide direction: moving right → new content comes from right */
  const direction = prev === null ? "left" : prev < active ? "left" : "right";

  return (
    <section style={{
      background: "#fff",
      padding: "100px 8vw 120px",
    }}>
      {/* ── Heading ── */}
      <div style={{ textAlign: "center", marginBottom: 60 }}>
        <h2 style={{
          fontFamily: "'Playfair Display','Georgia',serif",
          fontSize: "clamp(38px,6vw,90px)",
          fontWeight: 900, color: "#1a1a1a",
          lineHeight: 1.05, margin: "0 0 20px",
        }}>
          The people who<br />powered this evolution
        </h2>
        <p style={{
          fontSize: "clamp(15px,1.2vw,20px)",
          color: "#555", lineHeight: 1.7,
          maxWidth: 680, margin: "0 auto",
          fontFamily: "'Inter',sans-serif",
        }}>
          The gig workforce spans the entire supply chain, from first-mile
          operations to last-mile delivery.
        </p>
      </div>

      {/* ── Timeline bar ── */}
      <div style={{
        position: "relative",
        marginBottom: 56,
        maxWidth: 900,
        margin: "0 auto 56px",
      }}>
        {/* Horizontal line */}
        <div style={{
          position: "absolute",
          top: "50%", left: 0, right: 0,
          height: 2,
          background: "#e53e3e",
          transform: "translateY(-50%)",
          zIndex: 0,
        }}/>

        {/* Dots + Labels */}
        <div style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          position: "relative", zIndex: 1,
          padding: "0 60px",
        }}>
          {MILES.map((mile, i) => (
            <button
              key={mile.id}
              onClick={() => handleTabClick(i)}
              style={{
                background: "none", border: "none", cursor: "pointer",
                display: "flex", flexDirection: "column", alignItems: "center", gap: 10,
              }}
            >
              {/* Label above dot */}
              <span style={{
                fontFamily: "'Inter',sans-serif",
                fontSize: 15, fontWeight: 700,
                color: "#e53e3e",
                letterSpacing: 0.2,
                marginBottom: 4,
              }}>{mile.label}</span>

              {/* Dot */}
              <div style={{
                width: active === i ? 28 : 18,
                height: active === i ? 28 : 18,
                borderRadius: "50%",
                background: "#e53e3e",
                border: active === i ? "3px solid white" : "2px solid #e53e3e",
                boxShadow: active === i ? "0 0 0 3px #e53e3e" : "none",
                transition: "all 0.3s ease",
                position: "relative",
              }}>
                {/* Pulse ring on active */}
                {active === i && (
                  <span style={{
                    position: "absolute", inset: -6,
                    borderRadius: "50%",
                    border: "2px solid rgba(229,62,62,0.4)",
                    animation: "pulse-tab 1.5s ease-out infinite",
                  }}/>
                )}
              </div>
            </button>
          ))}
        </div>
      </div>

      <style>{`
        @keyframes pulse-tab {
          0%   { transform:scale(1);   opacity:0.8; }
          100% { transform:scale(1.7); opacity:0;   }
        }
      `}</style>

      {/* ── Animated content panel ── */}
      <div style={{
        maxWidth: 900, margin: "0 auto",
        overflow: "hidden",
        minHeight: 340,
      }}>
        {/* Active mile label top-left */}
        <p style={{
          fontSize: 13, fontWeight: 700, color: "#e53e3e",
          letterSpacing: 1, textTransform: "uppercase",
          marginBottom: 28,
          fontFamily: "'Inter',sans-serif",
        }}>{MILES[active].label}</p>

        <ContentPanel key={key} mile={MILES[active]} direction={direction} />
      </div>
    </section>
  );
}
